import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOSHUA = {
    "1": {
        "1": "<p>The book opens after Moses's death — and here the name-typology strikes first. <em>Yehoshua</em> (Joshua) means 'YHWH saves,' the precise Hebrew form from which <em>Iesous</em> (Jesus) derives. The author of Hebrews makes the identification explicit: 'If Joshua (<em>Iesous</em>) had given them rest, God would not have spoken of another day' (Heb 4:8). The Joshua who replaces Moses after his death is a deliberate type: as Moses (the Law) cannot bring the people into the final rest, so Joshua (the name of Jesus) leads them in. The entire book of Joshua is structured around this substitution — the Law leads to the border; only Jesus brings into the inheritance.</p>",
        "2": "<p>'Now therefore arise, go over this Jordan, you and all this people, into the land' — the Jordan crossing as baptism typology is anchored here at the command itself. Paul draws the Exodus-Jordan parallel in 1 Cor 10:1-2: 'all were baptized into Moses in the cloud and in the sea.' Origen extended this to the Jordan: the crossing from Transjordan into Canaan = passing through baptism into the promised inheritance. The command to cross carries Christological weight: Jesus himself was baptized in the Jordan (Matt 3:13-17), and his baptism opened the new era of conquest over sin and death. As Joshua's commission began at the Jordan, so Jesus's public ministry began at the Jordan.</p>",
        "3": "<p>A type: 'Every place that the sole of your foot will tread upon I have given to you.' The land-grant to Joshua types Christ's universal dominion granted by the Father: 'All authority in heaven and on earth has been given to me' (Matt 28:18). As Joshua's feet would tread the whole land and claim it, so Christ's resurrection enthronment claims every territory — he is 'far above all rule and authority and power and dominion' (Eph 1:20-21). The Psalm anticipates this: 'The LORD said to my Lord: sit at my right hand, until I make your enemies a footstool for your feet' (Ps 110:1). The whole land is already given before a single foot treads it — so the Father gave Christ all authority before the last enemy is put down.</p>",
        "4": "<p>The territorial extent of the promise — from the wilderness to Lebanon, from the Euphrates to the Great Sea — reflects the maximal reach of Israel's inheritance never fully realized under Joshua. The type presses toward anti-type: Christ's inheritance is not a strip of Levantine territory but the whole earth ('Ask of me, and I will make the nations your heritage, and the ends of the earth your possession,' Ps 2:8). Joshua's partial realization of a bounded land promise is the shadow; Christ's universal inheritance is the substance. The 'land flowing with milk and honey' that Joshua would enter is the prototype of the new creation that Christ inherits and shares with his people (Heb 11:10,16; Rev 21:1-4).</p>",
        "5": "<p>'No man shall be able to stand before you all the days of your life... I will not leave you or forsake you' — Heb 13:5 quotes this promise directly and applies it to every believer in Christ: 'For he has said, \"I will never leave you nor forsake you.\"' The promise given to Joshua is fulfilled in Christ and extended to all who are in Christ. Jesus's own promise echoes it verbatim: 'I am with you always, to the end of the age' (Matt 28:20). YHWH's personal presence with Joshua — the basis of every military victory — types the indwelling of the Spirit in believers, the presence that makes conquest of sin possible and guarantees the ultimate inheritance.</p>",
        "6": "<p>'Be strong and courageous, for you shall cause this people to inherit the land' — the commissioning formula given to Joshua is echoed in Paul's exhortation to Timothy ('Be strengthened by the grace that is in Christ Jesus,' 2 Tim 2:1) and to all believers ('Be strong in the Lord and in the strength of his might,' Eph 6:10). The phrase bridges Joshua's military commission and the spiritual warfare of the NT: the source of strength is the same divine presence, now mediated through Christ. Joshua's commission was for territorial conquest; Christ's commission to his disciples expands this to cosmic scope — 'make disciples of all nations' (Matt 28:19) — but the enabling presence is identical.</p>",
        "7": "<p>'Only be strong and very courageous, being careful to do according to all the law that Moses my servant commanded you' — Christ himself embodied this complete Torah-faithfulness: 'Do not think that I have come to abolish the Law or the Prophets; I have not come to abolish them but to fulfill them' (Matt 5:17). Joshua's success was conditioned on not turning 'to the right hand or to the left' from the Torah — Christ fulfilled this condition perfectly where every human failed. His 'not turning aside' from the Father's will through Gethsemane to the cross is the ultimate Joshua-type faithfulness: the conquest accomplished through absolute obedience to the divine command.</p>",
        "8": "<p>'This Book of the Law shall not depart from your mouth, and you shall meditate on it day and night' — the Word that Joshua was to meditate on was the written Torah; Christ is the Word incarnate (John 1:14). The meditation-command types the union of Christ with the Father's word: 'the words that I say to you I do not speak on my own authority, but the Father who dwells in me does his works' (John 14:10). The promise 'you will have good success' (<em>tatzliach</em>) is fulfilled in Christ through his resurrection — the ultimate vindication of the one who did not let the Word depart from his mouth. Those united to Christ now meditate on the word 'in him' (Col 3:16).</p>",
        "9": "<p>'Do not be frightened, and do not be dismayed, for the LORD your God is with you wherever you go' — Jesus speaks virtually this same word at the great commission: 'Fear not' is his characteristic word of resurrection courage (Matt 28:10; Rev 1:17). The basis of Joshua's fearlessness — divine presence — is the same basis of Christian fearlessness: 'I am with you always' (Matt 28:20). The disciples of Jesus face a conquest mission that is genuinely terrifying (Matt 10:16-39) and need exactly this reassurance. Christ does not send his people where he himself will not go — his presence is the conquest's guarantee, as it was for Joshua.</p>",
        "10": "<p>Joshua's command to the officers to prepare for the crossing within three days carries a resonance: it was after three days that the miracle of new creation occurred — the Jordan parted and Israel entered the land. The three-day preparation is a shadow of the three days of Christ's death and resurrection, after which the new humanity entered the new creation. As Israel's officers organized the crossing that would happen in three days, the disciples waited three days for the crossing that would change everything. The three-day cadence runs through the OT as a resurrection pattern (Jonah 1:17; Hos 6:2; Gen 22:4) before its definitive fulfillment in Matt 12:40.</p>",
        "11": "<p>'Prepare provisions for yourselves, for within three days you are to pass over this Jordan to go in to take possession of the land' — the command to prepare food for the crossing echoes the Last Supper, where Jesus prepared his disciples for the crossing through death into the new creation. 'Do this in remembrance of me' (Luke 22:19) is the provision for the journey through the Jordan of death and resurrection. The manna ceased when Israel ate the produce of the land (Josh 5:12); the Eucharist as 'food for the crossing' will be replaced by the marriage supper of the Lamb when the ultimate land is entered (Rev 19:9).</p>",
        "12": "<p>The Transjordanian tribes — Reuben, Gad, and half-Manasseh — were already settled but were obligated to cross and fight for their brothers before returning to their inheritance. This types the solidarity Christ showed in the incarnation: already possessing his eternal inheritance in the Father's presence, he 'crossed over' into our condition to fight for those who had not yet received their inheritance (Phil 2:5-8; Heb 2:14-15). As the settled tribes did not excuse themselves from their brothers' warfare, Christ did not excuse himself from humanity's warfare against sin and death. His incarnation is the crossing-over of the one who had every reason to remain on the far side.</p>",
        "13": "<p>'Remember the word that Moses the servant of the LORD commanded you: The LORD your God is providing you a place of rest' — the rest-promise (Hebrew <em>menucha</em>) carries forward into the NT's climactic rest theology. Hebrews 3-4 expounds this passage directly: the rest Joshua gave was a type pointing to the 'sabbath rest' that remains for the people of God (Heb 4:9). 'For whoever has entered God's rest has also rested from his works as God did from his' (Heb 4:10). The Transjordanian tribes' settled rest types believers who are already seated with Christ in the heavenly places (Eph 2:6) while still fighting the earthly battle.</p>",
        "14": "<p>The armed warriors crossing the Jordan to fight for the inheritance of those not yet settled types Christ's atoning work on behalf of those who could not win their own inheritance. 'While we were still sinners, Christ died for us' (Rom 5:8) — he crossed through death for the sake of those who lacked the righteousness to cross themselves. The image of the Transjordanian warriors going before their brothers 'armed' while the women and children remained is a picture of Christ as the warrior-champion who fights the decisive battle in the believer's place (Isa 59:16; 63:3-5). The 40,000 armed men crossing ahead of Israel type Christ as the forerunner who opens the way.</p>",
        "15": "<p>'Until the LORD gives rest to your brothers as he has to you, and they also take possession of the land' — the promise of rest for all the tribes is an eschatological vision: not one tribe left behind, not one member of the covenant community excluded from the inheritance. Christ's work has this same totalizing scope: 'I, when I am lifted up from the earth, will draw all people to myself' (John 12:32). The Transjordanian tribes will receive their full rest only when all Israel has received its rest — Christ's own 'rest' in his resurrection glory is complete only when the full number of his people is gathered (Rev 6:11).</p>",
        "16": "<p>The elders' covenant-loyalty declaration — 'All that you have commanded us we will do, and wherever you send us we will go' — types the covenant response that Christ secured for his people. What Israel promised here but failed to sustain, Christ accomplished in his own perfect obedience: 'My food is to do the will of him who sent me and to accomplish his work' (John 4:34). Moreover, the Spirit of Christ given at Pentecost creates this covenant responsiveness in believers: 'I will put my Spirit within you, and cause you to walk in my statutes' (Ezek 36:27). The obedience Israel pledged in words, Christ fulfilled in actuality, and the Spirit reproduces in the new covenant community.</p>",
        "17": "<p>'Just as we obeyed Moses in all things, so we will obey you' — the transfer of covenant loyalty from Moses to Joshua types the transfer from Torah to Christ. Paul's argument in Galatians and Romans is precisely this: the Mosaic administration has served its purpose and given way to the Joshua-administration. 'For Christ is the end of the law for righteousness to everyone who believes' (Rom 10:4). Those in Christ have transferred their primary covenant allegiance from Moses (the written code) to Jesus (the living Lord). The death penalty for rebellion against Joshua's command (v.18) anticipates the gravity of rejecting Christ: 'How shall we escape if we neglect such a great salvation?' (Heb 2:3).</p>",
        "18": "<p>'Only be strong and courageous' — the people's charge to Joshua mirrors YHWH's earlier words back to their leader, and the phrase closes Joshua 1 as a bookend of divine-and-human encouragement. For Christ, the Father's voice at his baptism ('This is my beloved Son, with whom I am well pleased,' Matt 3:17) is the divine encouragement that sends him into his conquest. The human confirmation came at the transfiguration (Matt 17:5) and in John 12:28 ('Father, glorify your name — and a voice came from heaven: I have glorified it, and I will glorify it again'). Christ's Joshua-commission was ratified both from above and from the human response of those who recognized his divine authority.</p>",
    },
    "2": {
        "1": "<p>The dispatch of two spies to Jericho — and their lodging with Rahab — sets up one of the NT's most prominent OT examples of faith (Heb 11:31; Jas 2:25). But Rahab's ultimate significance is genealogical: Matthew's genealogy of Jesus places her directly in the line of the Messiah — 'Salmon the father of Boaz by Rahab' (Matt 1:5). A Canaanite prostitute is in the bloodline of Jesus Christ. This is not incidental; the genealogy of Matthew is a theological statement about the kind of Messiah Jesus is — one who comes from the outcasts and Gentiles as well as from Israel's heroes, fulfilling God's purpose to bless all nations through Abraham's seed (Gen 12:3).</p>",
        "2": "<p>The king of Jericho's intelligence report — 'men of Israel have come here tonight to search out the land' — is the first of many rejections and hostile searchings that prefigure Israel's (and ultimately humanity's) resistance to Christ. As Jericho's king sought to capture the spies who brought the word of YHWH's conquest, Herod sought to kill the infant Jesus who would accomplish the ultimate conquest (Matt 2:13-16). The pattern of the powers of this age mobilizing against YHWH's agents of redemption runs through the whole Bible, from Pharaoh's infanticide to Herod's massacre — the adversary always knows that his kingdom is threatened and responds with rejection and force.</p>",
        "3": "<p>The king's demand — 'bring out the men who have come to you' — is Jericho's self-determined judgment: the city that rejected YHWH's messengers sealed its own doom. Jesus pronounces the same judgment pattern on cities that reject his messengers: 'And if anyone will not receive you or listen to your words, shake off the dust from your feet when you leave that house or town. Truly, I say to you, it will be more bearable on the day of judgment for the land of Sodom and Gomorrah than for that town' (Matt 10:14-15). Jericho's rejection of the spies (YHWH's advance agents) anticipates the rejection that leads to judgment — but Rahab's reception creates an island of salvation within the doomed city.</p>",
        "4": "<p>Rahab's concealment of the spies and her deception of the king's messengers types the hidden nature of God's people in the midst of a world hostile to Christ. The church is 'hidden with Christ in God' (Col 3:3); the world does not know believers as it did not know Christ (1 John 3:1). Rahab's house was a place of secret salvation within a city of certain judgment — a picture of the church as the community of the saved dwelling within the world under divine sentence. The king's failure to find the spies types the powers' failure to extinguish the gospel: 'The light shines in the darkness, and the darkness has not overcome it' (John 1:5).</p>",
        "5": "<p>The closed gate of Jericho at nightfall types the closing of the age — the moment when no further entrance is possible. Jesus warns of this closure: 'Strive to enter through the narrow door. For many, I tell you, will seek to enter and will not be able. When once the master of the house has risen and shut the door...' (Luke 13:24-25). Rahab's act of concealment happened before the gate closed — salvation is available within the time of opportunity, before the door shuts. The urgency of the gospel is this: Jericho's gate closes; the moment for safe passage is now.</p>",
        "6": "<p>The flax stalks under which the spies were hidden on Rahab's roof carry a hidden-life symbolism that resonates with the hiddenness of the risen Christ in the world. 'Your life is hidden with Christ in God' (Col 3:3) — believers are concealed under something ordinary (the flat roof, the mundane life of the world) while the enemy searches. The spies' survival depended entirely on Rahab's concealment — as believers' lives depend entirely on Christ's concealment of them in himself. The enemy cannot find what Christ has hidden.</p>",
        "7": "<p>The king's men pursuing the spies toward the Jordan ford types the futile pursuit of those whom Christ has freed. As Pharaoh's army pursued Israel to the Red Sea and was destroyed there (Exod 14:28), Jericho's men pursued the spies toward the Jordan — the very water that would eventually destroy Jericho's power. The Jordan becomes the boundary that defines safety: those on YHWH's side of the Jordan are under his protection; those pursuing them are on the side of the condemned city. The pursuit ends at the crossing-point, which types baptism — those united to Christ through death and resurrection are beyond the reach of condemnation (Rom 8:1).</p>",
        "8": "<p>Rahab's pre-sleep declaration to the spies (vv.9-11) is among the great confessions of faith in the OT — made before any visible result, based entirely on what she had heard (<em>shama'nu</em>, 'we have heard'). This faith pattern is paradigmatic: 'So faith comes from hearing, and hearing through the word of Christ' (Rom 10:17). Rahab believed on the basis of testimony about YHWH's acts — the Red Sea, Sihon, Og — without having witnessed any of them. She types the Gentile believer who hears the gospel, receives it by faith, and acts on it before the visible conquest arrives. Heb 11:31 identifies her explicitly as one who acted by faith.</p>",
        "9": "<p>'I know that the LORD has given you the land' — Rahab's confession is a perfect expression of the faith that grasps divine promise as done before it is historically visible. 'Faith is the assurance of things hoped for, the conviction of things not seen' (Heb 11:1). Rahab's 'I know' (<em>yada'ti</em>) reflects the same certainty that Paul expresses: 'I know whom I have believed, and I am convinced that he is able to guard until that day what has been entrusted to me' (2 Tim 1:12). The Gentile prostitute models the NT's definition of saving faith — certainty based not on present evidence but on the word of a faithful God.</p>",
        "10": "<p>Rahab's specific knowledge of YHWH's acts — the parting of the Red Sea and the defeat of Sihon and Og — is 'the word about Christ' before Christ came (1 Pet 1:10-12). The prophets who spoke of grace to come 'searched and inquired carefully, inquiring what person or time the Spirit of Christ in them was indicating when he predicted the sufferings of Christ and the subsequent glories.' Rahab heard the reports of YHWH's mighty acts and drew the correct theological conclusion: this God is the real God, and he is coming to claim his land. The NT equivalent is hearing the word of the cross and resurrection and drawing the same conclusion: this God is real, and he is coming to claim his world.</p>",
        "11": "<p>'For the LORD your God, he is God in the heavens above and on the earth beneath' — Rahab's confession is monotheistic in form and function. She renounces the entire Canaanite pantheon in a single declaration, naming YHWH as the only real God. This confession parallels the NT's repeated assertion that Christ is Lord over all competing powers: 'that at the name of Jesus every knee should bow, in heaven and on earth and under the earth' (Phil 2:10). Rahab's conversion is the advance guard of the Gentile mission: before a single city fell, a Gentile had already confessed YHWH as the only God and transferred her allegiance. She is Abraham's spiritual daughter before she becomes Christ's biological ancestor.</p>",
        "12": "<p>Rahab's request for <em>hesed</em> (covenant loyalty, faithful love) in exchange for her loyalty is the earliest picture of Gentile inclusion in the covenant of grace. She asks to be included in the covenant community on the basis of her demonstrated faith — and is granted it. The NT's inclusion of Rahab in the genealogy of Jesus (Matt 1:5) and in the hall of faith (Heb 11:31) confirms that her covenant status was genuine. She types every Gentile who receives covenant inclusion through faith in Christ: 'Remember that you were at that time separated from Christ, alienated from the commonwealth of Israel... but now in Christ Jesus you who once were far off have been brought near by the blood of Christ' (Eph 2:12-13).</p>",
        "13": "<p>Rahab's plea for the lives of 'my father and mother, my brothers and sisters, and all who belong to them' — the whole household — types the household-salvation pattern of the NT. Cornelius's household, the Philippian jailer's household, Lydia's household — the NT's salvation events consistently extend to the whole family unit (Acts 10:2; 16:31-34; 16:15). The promise 'believe in the Lord Jesus, and you will be saved, you and your household' (Acts 16:31) echoes the Rahab type: covenant salvation extends through the believing member to the whole household connected to them. The house marked by the scarlet cord was the unit of salvation.</p>",
        "14": "<p>'Our life for yours even to death' — the spies' oath to Rahab prefigures Christ's own oath to those who trust him. He stakes his life for theirs — literally. 'Greater love has no one than this, that someone lay down his life for his friends' (John 15:13). The conditional protection the spies offered ('if you do not tell this business of ours') is replaced in Christ by unconditional covenant faithfulness — 'nothing will separate us from the love of God in Christ Jesus our Lord' (Rom 8:38-39). The spies could only promise protection contingent on Rahab's continued silence; Christ's protection is unconditional, resting on his own righteousness rather than on the protected one's performance.</p>",
        "15": "<p>Rahab's letting the spies down through her window by a rope types the 'rope' connections that run through salvation history — Paul was let down through a window in a basket at Damascus to escape arrest (2 Cor 11:33), echoing the Rahab escape. More theologically, the 'way out' from the doomed city through the window in the wall types Christ as the escape route through the barrier of death: 'I am the door. If anyone enters by me, he will be saved' (John 10:9). Rahab's house in the wall provided the one opening through which the condemned could escape judgment — Christ is the one opening through which humanity escapes the condemned creation.</p>",
        "16": "<p>The three days the spies hid in the hill country before returning to Joshua carries the resurrection pattern: three days of concealment followed by return and report. Jonah's three days in the whale, Isaac's three-day journey to Moriah, and these three days of the spies' hiding all participate in the pattern that Jesus identified as his own sign: 'For just as Jonah was three days and three nights in the belly of the great fish, so will the Son of Man be three days and three nights in the heart of the earth' (Matt 12:40). The hidden-alive-for-three-days pattern is YHWH's signature on the resurrection narrative before it occurs historically.</p>",
        "17": "<p>The conditions of the spies' oath — the scarlet thread in the window, the family gathered inside, silence maintained — type the conditions of salvation in Christ. The one condition is not works but identification with the covenant sign: those who are 'inside' (in Christ, marked with his blood-sign) are safe; those who go outside are exposed to judgment. The parallel to Passover (blood on the doorposts, remaining inside the house, Exod 12:22-23) is deliberate: two covenant-blood-marking events frame the exodus and the conquest, both requiring the same response — stay under the blood, remain inside. Christ is the one in whom the saved remain (John 15:4-5).</p>",
        "18": "<p>A type: 'Tie this scarlet cord in the window and bring your father and mother, your brothers, and all your father's household into your house.' The scarlet cord (<em>tikvat chut hashani</em>) is the most explicitly Christological symbol in the Rahab narrative. Patristic interpreters from Justin Martyr onward identified the scarlet cord with the blood of Christ: 'The scarlet thread which the spies told Rahab to tie in the window is the sign of the blood of Christ, by which those who were formerly harlots and iniquitous persons are saved' (Justin Martyr, <em>Dialogue with Trypho</em> 111). The Hebrew <em>tikvah</em> means both 'cord' and 'hope' — the scarlet cord is the hope, the sign of blood that distinguishes the saved from the condemned. 1 Pet 1:18-19 names the blood of Christ as the redemption price; the cord in Rahab's window is its first visible type.</p>",
        "19": "<p>'His blood shall be on his own head' — the blood-responsibility formula here is the mirror image of the crowd's declaration at Jesus's trial: 'His blood be on us and on our children!' (Matt 27:25). The Jericho judgment fell on those who rejected the sign and went outside Rahab's house; the gospel's blood-responsibility falls on those who reject Christ's blood as the covenant sign. The protection Rahab's household received by staying under the scarlet sign types the protection believers receive by remaining in Christ — those who 'go out' from the community of faith (1 John 2:19) put themselves outside the zone of covenant protection.</p>",
        "20": "<p>The silence required of Rahab — 'if you tell this business of ours' — has a parallel in the so-called 'messianic secret' of Mark's Gospel: Jesus repeatedly commands silence about his identity during the conquest phase of his ministry (Mark 1:44; 3:12; 5:43; 7:36; 8:30). The timing of revelation matters in YHWH's warfare: premature disclosure disrupts the plan. Rahab's maintained silence protected the spies' mission; the disciples' maintained silence (until the resurrection) protected the unfolding of the conquest of death. In both cases, the appointed time for full disclosure comes after the victory is accomplished.</p>",
        "21": "<p>Rahab's tying of the scarlet cord 'in the window' is the act of covenant ratification — she identified her house as belonging to YHWH's side before the battle was fought. This is baptism in its functional logic: 'In him also you were circumcised with a circumcision made without hands... having been buried with him in baptism, in which you were also raised with him through faith' (Col 2:11-12). The external sign of the scarlet cord publicly marked Rahab's transfer of allegiance before any visible rescue occurred. Faith marks itself externally — the cord in the window, the baptismal waters, the Lord's Supper — as a visible declaration of covenant identity under the blood.</p>",
        "22": "<p>The three-day hiding in the hill country, away from the Jordan, before the return to Joshua — three days in a kind of death-hiding, three days before the return to the commander who will bring life — types the three days of Christ's burial. The disciples scattered to the hills (Mark 14:50) and hid behind locked doors (John 20:19) in exactly the same way: three days of terrified hiding before the return of the one who brings life. The spies returned and reported 'Truly the LORD has given all the land into our hands' — the disciples returned and reported 'He has risen' (Matt 28:8). Both reports are the same theological announcement: YHWH has already given the victory.</p>",
        "23": "<p>The spies' return and report — 'Truly the LORD has given all the land into our hands, and also all the inhabitants of the land melt away because of us' — is a resurrection-announcement pattern. The risen Christ's own words echo this: 'All authority in heaven and on earth has been given to me' (Matt 28:18). Both announcements use the perfect/accomplished tense: the victory is already given, already achieved, even though the visible conquest has not yet been completed. The Christological pattern is 'already-not-yet': the land is given (the resurrection has happened), but the conquest of each city still lies ahead (the sanctification and final parousia are still in process).</p>",
        "24": "<p>'Truly the LORD has given all the land into our hands, and also all the inhabitants of the land melt away because of us' — the spies' report is the conquest's prologue and promise. This is the hermeneutical key to the entire book: what YHWH has declared accomplished by promise, Israel must now actualize by faith. The NT applies the same logic to Christ's victory over sin and death: 'The God of peace will soon crush Satan under your feet' (Rom 16:20) — the victory is Christ's (Rom 16:20a, 'The God of peace will crush Satan'), but it is actualized in the believer's life ('under your feet'). The spies' confident report types the apostolic proclamation: the victory is given; go and take possession.</p>",
    },
    "3": {
        "1": "<p>The move from Shittim to the Jordan's edge is the threshold moment — the last point before the crossing. Shittim was the site of Israel's greatest failure in the wilderness (Num 25, Baal Peor), so the march from Shittim to the Jordan marks the movement from failure to redemption. Christ's own path to the Jordan — from his birth in the world's Shittim (the place of failure, the cursed creation) to his baptism in the Jordan — follows the same arc. His baptism is not his own repentance but his solidarity with the sinners who need redemption. As Israel stood at the Jordan to cross into new life, Jesus stood at the Jordan to open a new humanity.</p>",
        "2": "<p>The three-day wait at the Jordan before the crossing — the officers going through the camp on the third day — maintains the three-day resurrection pattern that runs through the conquest narrative. Three days at the Red Sea (Exod 14-15); three days of the spies' hiding (Josh 2:22); three days at the Jordan (Josh 1:11, 3:2); three days at Gilgal (Josh 5:8 — healing after circumcision). This accumulation of three-day intervals is the OT's way of marking the events that participate in YHWH's resurrection logic. Jesus identified this logic himself: 'Destroy this temple, and in three days I will raise it up' (John 2:19). The Jordan crossing is a resurrection event — a passing through death (the flooded river) into new life.</p>",
        "3": "<p>The command to follow the Ark at a distance — 'that you may know the way you shall go, for you have not passed this way before' — types Christ as the forerunner through death. 'We have this as a sure and steadfast anchor of the soul, a hope that enters into the inner place behind the curtain, where Jesus has gone as a forerunner on our behalf' (Heb 6:19-20). The Ark going before Israel through the Jordan types Christ going before his people through death — he has already crossed the Jordan of death and resurrection; believers follow him on the path he opened. The instruction 'you have not passed this way before' is literally true of death: no one has passed through to resurrection before Christ. He opens the way.</p>",
        "4": "<p>The 2,000-cubit gap between the people and the Ark — 'do not come near it' — marks the holiness-distance that the unconsecrated cannot cross. This gap is the problem that Christ resolves: 'For Christ also suffered once for sins, the righteous for the unrighteous, that he might bring us to God' (1 Pet 3:18). The veil of the temple, torn at Christ's death (Matt 27:51), is the 2,000-cubit gap abolished — 'we have confidence to enter the holy places by the blood of Jesus, by the new and living way that he opened for us through the curtain, that is, through his flesh' (Heb 10:19-20). The required distance between Israel and YHWH's presence was the old covenant's structure; Christ's atonement collapses it.</p>",
        "5": "<p>'Sanctify yourselves, for tomorrow the LORD will do wonders among you' — the command to be holy before the miraculous crossing types baptismal preparation in the NT (1 Cor 6:11; Titus 3:5) and the eschatological preparation for Christ's coming: 'Beloved, we are God's children now, and what we will be has not yet appeared; but we know that when he appears we shall be like him, because we shall see him as he is. And everyone who thus hopes in him purifies himself as he is pure' (1 John 3:2-3). The 'wonders' (<em>nifla'ot</em>) YHWH was about to do are the same category as the cross and resurrection — the miraculous acts of divine power that change the course of history.</p>",
        "6": "<p>The Levitical priests carrying the Ark before the people into the Jordan types Christ bearing his cross — and with it, all humanity's sin — into death. 'He himself bore our sins in his body on the tree' (1 Pet 2:24). The priests carried the Ark (YHWH's covenant presence) into the flooded river; Christ carried the covenant curse into death itself. The priests stood in the riverbed throughout the crossing — Christ remained in death for three days — until all the people had safely crossed. His 'standing in death' (the three days of burial) held open the way of salvation for all who would cross through him. Then the waters returned — the resurrection sealed off death's power.</p>",
        "7": "<p>'Today I will begin to exalt you in the sight of all Israel' — YHWH's promise to exalt Joshua at the Jordan types the Father's exaltation of Christ through the resurrection: 'God has highly exalted him and bestowed on him the name that is above every name' (Phil 2:9). The Jordan crossing was the moment of Joshua's public legitimation as Moses's true successor; the resurrection was the moment of Christ's public legitimation as the Son of God 'with power' (Rom 1:4). 'It was declared with power' — the Jordan miracle declared Joshua's authority with power; the resurrection declared Christ's authority with the same divine power. Both exaltations are YHWH's vindication of his appointed servant.</p>",
        "8": "<p>The priests standing in the Jordan — holding back the waters by their stationary presence with the Ark — types Christ 'standing' in death and holding open the crossing for all believers. The image of immovable priests in the flooded riverbed is a picture of Christ's faithfulness in the midst of the worst ordeal: 'He endured the cross, despising the shame' (Heb 12:2). The priests did not run from the flood waters; Christ did not draw back from the cup of God's wrath (Matt 26:39-42). Their motionlessness in the Jordan was the condition of every Israelite's safe crossing; Christ's steadfast endurance of the cross is the condition of every believer's safe passage through death.</p>",
        "9": "<p>'Come here and hear the words of the LORD your God' — the assembly of Israel at the Jordan to hear the divine word before crossing types every moment where Christ calls his people to hear before they act. 'My sheep hear my voice, and I know them, and they follow me' (John 10:27). The Jordan crossing was not a spontaneous movement but an ordered response to heard words — the miracle followed the word, not precedes it. The NT pattern is identical: faith comes by hearing (Rom 10:17); the miracle of new birth follows the word of the gospel. Joshua assembling Israel at the Jordan to hear YHWH's word is the OT template for the gospel preacher assembling the nations before the water of baptism.</p>",
        "10": "<p>'Hereby you shall know that the living God is among you' — the title 'living God' (<em>El chai</em>) occurs here before the Jordan miracle and is the same title Peter uses at Caesarea Philippi: 'You are the Christ, the Son of the living God' (Matt 16:16). The Jordan miracle was YHWH's self-revelation as the living God who acts in history; the resurrection is Christ's self-revelation as the Son of the same living God. Both events prove the same thing: this is not a dead deity but the living God who defeats death. The seven Canaanite nations about to be driven out type the powers and principalities that Christ defeated through the cross (Col 2:15): 'He disarmed the rulers and authorities and put them to open shame.'</p>",
        "11": "<p>'Behold, the ark of the covenant of the Lord of all the earth is passing over before you into the Jordan' — the title 'Lord of all the earth' (<em>adon kol ha'aretz</em>) applied to the Ark-carrying procession types the Christ who in his death and resurrection claimed universal lordship. 'He is Lord of all' (Acts 10:36). The Ark crossing the Jordan first is YHWH claiming sovereignty over Canaan before a single Israelite foot trod the new land. Christ's resurrection is the Father's advance declaration of his Son's universal lordship before the fullness of the nations has been gathered: 'The earth is the Lord's, and the fullness thereof' (Ps 24:1), declared and applied through Christ's cross.</p>",
        "12": "<p>The twelve men selected (one per tribe) to take memorial stones from the Jordan riverbed type the twelve apostles whom Christ selected to be the memorial witnesses of his resurrection. 'You will be my witnesses' (Acts 1:8) — as each tribal representative carried a stone from the miracle site, each apostle carried the testimony of the resurrection from the encounter with the risen Christ. The twelve stones at Gilgal became the visible memorial of the Jordan crossing; the twelve apostolic witnesses became the foundation of the church built on the resurrection (Eph 2:20). The number twelve is not accidental in either case — it is the number of covenantal completeness, the whole new Israel represented in the memorial bearers.</p>",
        "13": "<p>'The waters of the Jordan shall be cut off from the waters that come down from above, and they shall stand in one heap' — the cutting off of the upper waters at Adam types Christ as the one who 'cut off' the downward flow of sin's condemnation. 'There is therefore now no condemnation for those who are in Christ Jesus' (Rom 8:1) — the condemnation that was 'flowing down from above' (from divine judgment above into human history) is cut off by the one who bore it at the cross. The heap of water standing upstream is the accumulated wrath of God absorbed by Christ ('all your waves and billows have gone over me,' Ps 42:7; 88:7), held back by his atoning work so that the crossing can be made safely.</p>",
        "14": "<p>The priests bearing the Ark step toward the Jordan 'when the people set out from their tents' — the crossing begins with corporate movement, faith expressed in community. The NT salvation event has the same communal structure: 'where two or three are gathered in my name, there am I among them' (Matt 18:20). The individual cannot cross alone — the whole people move together, following the Ark. The Jordan crossing as corporate salvation act types baptism as incorporation into the body: 'For in one Spirit we were all baptized into one body' (1 Cor 12:13). The 'tents' they left behind type the earthly tabernacle of the body: 'We know that if the tent that is our earthly home is destroyed, we have a building from God' (2 Cor 5:1).</p>",
        "15": "<p>'The feet of the priests bearing the Ark were dipped in the brink of the water' — the priests' first step into the flood-Jordan before the miracle preceded the miracle. This is the faith-before-sight pattern that characterizes the entire Christ-event. Thomas demanded sight before faith (John 20:25); Christ commended those who believe without seeing (John 20:29). The priest who stepped into the flooded Jordan did not see the waters part before his feet touched the water — the miracle came with the step, not before it. 'Now faith is the assurance of things hoped for, the conviction of things not seen' (Heb 11:1). The priestly foot in the Jordan is the image of faith stepping into impossible territory in reliance on YHWH's word alone.</p>",
        "16": "<p>The waters standing 'in a heap, very far away, at Adam' — the place-name Adam carries an unmistakable typological charge. The flooding waters of divine judgment were stopped 'at Adam' — at the point of origin of humanity's problem. Christ's atonement went all the way back to Adam: 'For as in Adam all die, so also in Christ shall all be made alive' (1 Cor 15:22). The flood held back at Adam is the curse of Adam's sin held back by Christ's atonement. The water that 'flowed down into the Sea of the Arabah (the Dead Sea)' — the waters of death flowing away to the place of death — types the removal of condemnation. 'He has taken it out of the way, nailing it to the cross' (Col 2:14).</p>",
        "17": "<p>'And the priests bearing the Ark of the covenant of the LORD stood firm on dry ground in the midst of the Jordan, while all Israel was passing over on dry ground' — the priests standing firm while Israel crossed types Christ standing firm in death while his people pass through safely. 'For our sake he made him to be sin who knew no sin, so that in him we might become the righteousness of God' (2 Cor 5:21). Christ 'stood in' the Jordan of divine judgment — not for himself (he was without sin) but for all who would cross through him. His standing in the dry riverbed was neither for his own sake nor his own crossing; he stood there entirely for the sake of the people passing through. This is substitutionary atonement in its most vivid spatial image.</p>",
    },
    "4": {
        "1": "<p>The command to take twelve stones from the Jordan 'from the place where the priests' feet stood firm' carries sacramental significance. The stones are taken from the exact location where YHWH's presence accomplished the miracle — the holiest ground in the crossing. They become portable witnesses to the power of divine presence. The NT sacraments function analogously: water, bread, and wine taken from ordinary creation are placed in the context of Christ's salvific action and become memorials of the event in which he stood firm for his people. The materials themselves do not contain power; they point to the event in which divine power was manifest.</p>",
        "2": "<p>The twelve men — one from each tribe — are the representative witnesses whose stones become the memorial. The apostolic pattern is precisely this: twelve representative witnesses of the resurrection are sent to all tribes and nations with the testimony. 'You will be my witnesses in Jerusalem and in all Judea and Samaria, and to the end of the earth' (Acts 1:8). The twelve apostles are the NT equivalent of the twelve stone-bearers: representative members of the new Israel who carry the memorial of the crossing (the resurrection testimony) from the site of the miracle to all the nations. The memorial is not a stone monument but a living community of witnesses.</p>",
        "3": "<p>The stones are to be set up at 'the place where you lodge tonight' — Gilgal, the base camp of the conquest. The Christological reading: the memorial of Christ's crossing through death is established at the church's base camp, the place where the community returns and prepares for each new campaign. The Lord's Supper is this base-camp memorial: 'Do this in remembrance of me... For as often as you eat this bread and drink the cup, you proclaim the Lord's death until he comes' (1 Cor 11:24-26). The Eucharist is the Gilgal stone circle — the constantly-renewed memorial of the crossing accomplished, setting the camp of the church in its position for the ongoing conquest.</p>",
        "4": "<p>Joshua's calling of the twelve appointed men to carry the stones back from the Jordan riverbed types Christ's calling of the twelve apostles: chosen in advance (Eph 1:4; John 15:16), commissioned for a specific memorial task (Matt 28:19-20), and sent back into the world (the Jordan's crossing-place) to carry the testimony of the resurrection. 'As the Father has sent me, even so I am sending you' (John 20:21). The twelve men called by Joshua had been pre-appointed (3:12) — as the twelve apostles were pre-appointed and known to Christ before the resurrection (John 6:70; 13:18).</p>",
        "5": "<p>'Pass on before the Ark of the LORD your God into the midst of the Jordan, and take up each of you a stone upon his shoulder' — the command to carry a stone on the shoulder has a specific NT echo: 'whoever does not take his cross and follow me is not worthy of me' (Matt 10:38). The stones carried from the Jordan riverbed on the shoulders of the twelve men type the cross carried on the shoulders of Christ's disciples. The stone (the memorial burden) is carried out of the place of death (the Jordan riverbed) into the place of life (Gilgal) — as the cross (the burden of discipleship) is carried out of the old life into the new. Each man carries one stone; each disciple carries one cross.</p>",
        "6": "<p>'That this may be a sign among you. When your children ask in time to come, \"What do those stones mean to you?\"' — the catechetical function of the memorial stones types the NT's catechesis around the Lord's Supper: 'For as often as you eat this bread and drink the cup, you proclaim the Lord's death until he comes' (1 Cor 11:26). The children's question ('What do these stones mean?') is the structural equivalent of the new believer's inquiry at the Lord's Table: 'What does this bread and cup mean?' Both answers are the same type of answer: 'On this day, YHWH/Christ acted, and we live because he crossed through death for us.' The sacrament is a visible question-prompt for the oral proclamation of the saving event.</p>",
        "7": "<p>'These stones shall be to the people of Israel a memorial forever' — the 'forever' memorial of the Jordan crossing types the 'until he comes' of the Lord's Supper. Both memorials are temporally bounded: the Jordan stones were a memorial until the stones themselves were lost or the community dispersed; the Lord's Supper is 'until he comes.' The eschatological horizon of the Eucharist — anticipating the fulfillment when the memorial is superseded by the presence of the one remembered — corresponds to the Jordan stones anticipating the full inheritance of the land. When the land is fully possessed, the memorial of the crossing becomes less urgent; when Christ returns, the memorial supper is replaced by the feast itself (Rev 19:9).</p>",
        "8": "<p>'The people of Israel did just as Joshua commanded' — the obedience-formula that marks successful completion in Joshua types the church's obedience to Christ's commands: baptism and the Lord's Supper practiced 'as he commanded.' 'Go therefore and make disciples of all nations, baptizing them in the name of the Father and of the Son and of the Holy Spirit, teaching them to observe all that I have commanded you' (Matt 28:19-20). The stone-memorial was established by Israel's obedient execution of Joshua's command; the sacramental memorials of the church are established by the community's obedient execution of Christ's command. Sacraments without Christ's command are empty rituals; with his command, they are covenant acts.</p>",
        "9": "<p>The twelve stones set in the Jordan riverbed itself — the underwater monument — types the 'hidden' memorial of Christ's work in the depths of death. Christ's descent into death left a permanent mark: 'When he ascended on high he led a host of captives' (Eph 4:8, citing Ps 68:18). The Jordan riverbed monument was visible only at low water, a hidden memorial of the miracle. Christ's descent into Hades (1 Pet 3:18-20) is this underwater monument — the memorial of his victory in the very depths of death, visible to those with eyes to see but hidden from ordinary perception. 'They are there to this day' — the victory accomplished in death's depths is permanent.</p>",
        "10": "<p>'The priests who bore the Ark remained standing in the midst of the Jordan until everything was finished that the LORD commanded Joshua to tell the people' — the priests stood until 'everything was finished.' Jesus's cry from the cross — 'It is finished' (<em>tetelestai</em>, John 19:30) — is the definitive fulfillment of this priestly standing until completion. As the priests could not leave the Jordan until all Israel had crossed, Christ could not descend from the cross until the atonement was complete. 'The people hurried and crossed' — as the urgency in the Jordan crossing drove Israel forward, so the urgency of the gospel drives the church's mission. The priests stood; Christ stayed on the cross; not until 'everything was finished' could the holy act be declared complete.</p>",
        "11": "<p>The Ark crossing last — after all the people, as the rear guard — types Christ as both forerunner and rear guard. He went before into death (forerunner, Heb 6:20), and he comes behind the church as the one who guards its back. 'The LORD will go before you, and the God of Israel will be your rear guard' (Isa 52:12). As the Ark crossed last and the waters returned behind it (4:18), so Christ's ascension sealed off death behind him — the resurrection body cannot die again (Rom 6:9), and the way opened by Christ through death remains open for all who follow. The return of the waters did not trap Israel; it sealed the completed crossing. Christ's ascension does not close the way; it confirms the crossing is accomplished.</p>",
        "12": "<p>The Transjordanian warriors crossing 'armed in front of the people of Israel' — fulfilling their obligation before returning to their own inheritance — types the missionary church crossing into the world 'armed' with the gospel before entering the final rest. 'For we do not wrestle against flesh and blood, but against the rulers, against the authorities, against the cosmic powers over this present darkness' (Eph 6:12). The spiritual armor of Ephesians 6 corresponds to the warriors' military equipment at the Jordan: not physical weapons but the weapons of truth, righteousness, faith, salvation, the word of God. The church is always the Transjordanian warrior — already inheriting in Christ (Eph 2:6), but still fighting for the full possession of the land.</p>",
        "13": "<p>The 40,000 armed warriors crossing the Jordan types the great multitude who pass through the waters of death in Christ — 'the great multitude that no one could number, from every nation, from all tribes and peoples and languages, standing before the throne' (Rev 7:9). Forty is the number of wilderness testing and preparation; 40,000 (forty × one thousand) types the complete number of those prepared and consecrated by the wilderness experience who finally enter the inheritance. The complete number of the redeemed is not yet known — 'a great multitude that no one could number' — but it will be the full army of the Lord, all armed and ready for the final conquest.</p>",
        "14": "<p>'On that day the LORD exalted Joshua in the sight of all Israel, and they feared him just as they had feared Moses, all the days of his life' — the exaltation of Joshua after the Jordan miracle types the exaltation of Christ after the resurrection. 'This Jesus God raised up... Let all the house of Israel therefore know for certain that God has made him both Lord and Christ' (Acts 2:32,36). The people's awe before Joshua ('they feared him as they had feared Moses') types the church's posture before the risen Christ — reverent faith that recognizes divine authority confirmed by the miracle of new life. The resurrection is the Jordan miracle that establishes Christ's authority for all who witness it.</p>",
        "15": "<p>The chain of command — YHWH speaks to Joshua, Joshua commands the priests — maintained throughout the crossing narrative types the apostolic chain in the NT: Christ commissions the apostles, the apostles commission the church. 'As the Father has sent me, even so I am sending you' (John 20:21). The theological point is that authority flows through a specific chain of commission; the priests did not act on their own authority, and the apostles did not act on their own authority. Every step in the Jordan crossing was authorized by YHWH through Joshua; every step in the mission of the church is authorized by the Father through Christ through the apostolic tradition.</p>",
        "16": "<p>'Command the priests bearing the Ark of the testimony to come up out of the Jordan' — the priests could not exit the Jordan until commanded. Christ's resurrection was also not a self-initiated event but was declared by the Father: 'God raised him from the dead' (Acts 13:30; Rom 4:24; Gal 1:1). The Son did not raise himself; the Father raised the Son (John 5:21). The priests could not leave the Jordan on their own initiative; they waited for the command that would come through Joshua from YHWH. The dependence of the Son on the Father's command-to-rise types the structure of resurrection as divine act, not human achievement — 'it was not possible for him to be held by it' (Acts 2:24), not because he was too powerful but because death had no claim on the righteous one.</p>",
        "17": "<p>'So Joshua commanded the priests' — the moment of command is the moment of the resurrection's announcement. As Joshua's command set the priests in motion out of the Jordan, the Father's command (the divine decree of resurrection) set the Son in motion out of death. The 'command' is the operative category: the resurrection is not a natural resuscitation but a divine decree, YHWH overturning death's verdict on the one who was 'declared to be the Son of God in power according to the Spirit of holiness by his resurrection from the dead' (Rom 1:4). The priests emerged from the Jordan commanded; Christ emerged from death declared.</p>",
        "18": "<p>'As soon as the priests bearing the Ark of the covenant of the LORD came up from the midst of the Jordan, and the soles of the priests' feet were lifted up on dry ground, the waters of the Jordan returned to their place' — the moment the priests' feet left the water, the miracle reversed. The resurrection's consequence: death's door closed behind Christ (Rom 6:9, 'death no longer has dominion over him'). The Jordan flooding back types the definitive closure of death's claim on the risen Christ. 'He died once for all to sin' — the Jordan can only be crossed once; death can only be endured once by the atoning Christ. The return of the waters does not threaten the people who have crossed; it confirms that the crossing is complete and cannot be undone.</p>",
        "19": "<p>The arrival at Gilgal on the tenth of Nisan — the day of Passover lamb-selection — places the Jordan crossing in precise liturgical alignment with the Passover. The Christological reading of this calendar: Jesus, the Passover Lamb, entered Jerusalem on the tenth of Nisan (if Palm Sunday = Nisan 10) for his final Passover. The convergence of Joshua's Jordan-arrival on Nisan 10 with Jesus's Jerusalem-arrival on (approximately) Nisan 10 is not arbitrary; both events are moving within the liturgical calendar that YHWH appointed. The crossing of the Jordan is the beginning of the Passover week's consummation — as Jesus's entry into Jerusalem begins the week of his own Passover sacrifice.</p>",
        "20": "<p>The erection of the twelve Jordan stones at Gilgal types the apostolic foundation of the church. 'Built on the foundation of the apostles and prophets, Christ Jesus himself being the cornerstone' (Eph 2:20). The stones taken from the Jordan miracle site are the testimony of those who passed through — as the apostles' foundation role derives from their having been present at the resurrection, the definitive Jordan-crossing. Gilgal was the base camp from which all the campaigns of the conquest were launched; the apostolic foundation (the twelve stones) is the base camp from which the church's mission proceeds. No campaign moved without returning to Gilgal; no faithful ministry departs from the apostolic testimony.</p>",
        "21": "<p>'When your children ask their fathers in times to come, \"What do these stones mean?\"' — the pedagogical memorial points forward to the church's catechesis. The Great Commission includes 'teaching them to observe all that I have commanded you' (Matt 28:20) — the memorial that triggers the catechetical question. In Christian practice, the physical acts of baptism and the Lord's Supper serve as the children's question-provoking memorial: 'What does this water mean? What does this bread and cup mean?' The answer is always the same Jordan-testimony: 'YHWH divided the waters; Christ divided death — and we crossed through safely because of what he did.'</p>",
        "22": "<p>'You shall let your children know, \"Israel passed over this Jordan on dry ground\"' — the specific content of the catechetical answer is always the historical event, not a principle or a feeling. 'Israel passed over' — specific people, specific water, specific date. The NT's catechetical content is equally specific: 'that Christ died for our sins in accordance with the Scriptures, that he was buried, that he was raised on the third day in accordance with the Scriptures' (1 Cor 15:3-4). The Jordan testimony is not 'YHWH is powerful in general' but 'on this day, at this place, he did this specific thing.' Christian faith is anchored in historical particularity, as Joshua's faith was anchored in the specific day of the Jordan crossing.</p>",
        "23": "<p>'For the LORD your God dried up the waters of the Jordan for you until you passed over, as the LORD your God did to the Red Sea, which he dried up for us until we passed over' — the Jordan crossing interpreted through the Red Sea crossing is the OT pattern of reading new saving acts in light of prior ones. The NT reads Christ's cross and resurrection in light of both: 'Christ, our Passover lamb, has been sacrificed' (1 Cor 5:7); 'For I do not want you to be unaware, brothers, that our fathers were all under the cloud, and all passed through the sea, and all were baptized into Moses' (1 Cor 10:1-2). The catechism of salvation always connects events: sea → Jordan → Christ's baptism-death-resurrection. Each event illuminates the next.</p>",
        "24": "<p>'So that all the peoples of the earth may know that the hand of the LORD is mighty, and so that you may fear the LORD your God forever' — the universal purpose of the Jordan crossing (all peoples to know YHWH) is fulfilled in the Great Commission: 'Go therefore and make disciples of all nations' (Matt 28:19). The 'mighty hand' of YHWH that stopped the Jordan is the same hand revealed in Christ's resurrection. Peter's Pentecost sermon makes this explicit: 'This Jesus... you crucified and killed by the hands of lawless men. God raised him up, loosing the pangs of death, because it was not possible for him to be held by it' (Acts 2:23-24). The Jordan miracle was for all nations to witness YHWH's power; the resurrection is the definitive 'all nations' revelation of divine power over death.</p>",
    },
    "5": {
        "1": "<p>The psychological collapse of all the Canaanite kings upon hearing of the Jordan crossing — 'their hearts melted and there was no longer any spirit in them' — types the response of every power and principality to the resurrection of Christ. 'He disarmed the rulers and authorities and put them to open shame, by triumphing over them in him' (Col 2:15). The Canaanite kings were not merely militarily discouraged; they were theologically overwhelmed — their divine system had no answer to YHWH's Jordan miracle. The powers of darkness had no answer to Christ's resurrection — their ultimate weapon (death) had been defeated. The 'melting heart' of the Canaanite kings types the 'open shame' of the disarmed principalities after the cross.</p>",
        "2": "<p>The circumcision at Gilgal with flint knives types Christ's 'circumcision made without hands' — the death of the body of flesh in which he bore all sin. 'In him also you were circumcised with a circumcision made without hands, by putting off the body of the flesh, by the circumcision of Christ, having been buried with him in baptism' (Col 2:11-12). The Gilgal circumcision was the covenant-entry rite before the conquest battles; the circumcision of Christ (his death) is the covenant-entry event that opens the new creation. The flint knife cutting away the foreskin types the cross cutting away the 'body of flesh' — the sin-dominated human nature — that Christ bore in his death.</p>",
        "3": "<p>The 'Hill of the Foreskins' — Gibeath-haaraloth — became a named place precisely because of the covenant sign enacted there. The cross has the same naming power: 'Golgotha, which means Place of a Skull' (Matt 27:33) — the place where the ultimate circumcision occurred became permanently named for the event. As Gibeath-haaraloth was the site of the covenant sign that prepared Israel for conquest, Golgotha was the site of the covenant act that accomplished the ultimate conquest. Both are 'named hills of the covenant sign' — hills where the flesh was cut away so that the people could enter their inheritance.</p>",
        "4": "<p>The explanation of why the wilderness generation was uncircumcised — all who came from Egypt had died under judgment — types the condition of humanity before Christ: all who came from Adam's Egypt were under death's sentence and bore the uncircumcised flesh of the sin-nature. 'For all have sinned and fall short of the glory of God' (Rom 3:23). The wilderness generation's uncircumcised state was not accidental but the result of inherited judgment. Christ comes as the new Joshua to the generation born in the wilderness — those who have never been able to produce the righteousness the law demands — and performs the circumcision of the cross that the law-period could never accomplish.</p>",
        "5": "<p>The distinction between those who came out of Egypt (circumcised, under the old covenant) and those born in the wilderness (uncircumcised, needing the new covenant rite) types the transition from old to new covenant. The circumcised generation died in the wilderness — the old covenant generation did not enter the rest (Heb 3:17-19). The uncircumcised wilderness generation entered the land through the new Gilgal rite — the new covenant community enters the inheritance not through the old covenant circumcision but through the new. 'For in Christ Jesus neither circumcision nor uncircumcision counts for anything, but a new creation' (Gal 6:15). Gilgal's mass circumcision is simultaneously the end of the wilderness period and the beginning of the new creation.</p>",
        "6": "<p>'Forty years the people of Israel walked in the wilderness, until all the nation, the men of war who came out of Egypt, perished, because they did not obey the voice of the LORD' — the forty-year judgment types the period of the law's administration (Gal 3:19-25: 'the law was our guardian until Christ came'). The law kept Israel in the wilderness of inability; it could diagnose sin but not cure it. 'Now before faith came, we were held captive under the law, imprisoned until the coming faith would be revealed' (Gal 3:23). The disobedient generation that perished in the wilderness types those who trust in the law for righteousness and find only death; the Gilgal generation types those who receive the new covenant circumcision through faith in Christ.</p>",
        "7": "<p>'Their children, whom he raised up in their place, Joshua circumcised' — the raising up of children in place of the dead generation types the resurrection itself. 'For if we have been united with him in a death like his, we shall certainly be united with him in a resurrection like his' (Rom 6:5). The dead wilderness generation is replaced by the Gilgal generation as the old humanity is replaced by the new: 'The first man Adam became a living being; the last Adam became a life-giving spirit' (1 Cor 15:45). Christ as the last Adam is the ultimate 'child raised up in place of the dead' — the new humanity who succeeds where the first failed, receiving the inheritance that Adam forfeited.</p>",
        "8": "<p>The healing period after mass circumcision — the entire army vulnerable, waiting in camp — types the three days of Christ's death in which he was apparently vulnerable and defeated. On Good Friday and Holy Saturday, Christ lay in the tomb — the church appeared defenseless, the disciples scattered, the disciples' hopes destroyed. The Gilgal camp during healing was similarly: if Jericho's army had attacked in those days, Israel would have been destroyed. But YHWH's protection covered them — as the Father's purposes covered the three days of Christ's apparent vulnerability in the tomb. 'For you will not abandon my soul to Hades, or let your Holy One see corruption' (Acts 2:27, citing Ps 16:10). The healing period preceded the conquest's first victory.</p>",
        "9": "<p>'Today I have rolled away the reproach of Egypt from you' — the Gilgal etymology (<em>galal</em>, to roll) types the atonement's removal of sin's reproach. 'Christ redeemed us from the curse of the law by becoming a curse for us' (Gal 3:13). The 'reproach of Egypt' — the shame of slavery, uncircumcision, and divine judgment — was rolled away at Gilgal as the cross rolls away the reproach of sin, death, and divine condemnation. 'There is therefore now no condemnation for those who are in Christ Jesus' (Rom 8:1) — the Egypt-reproach is gone; the Gilgal-moment of the cross has occurred. The naming of Gilgal ('rolling') is YHWH's memorial of the atonement's shame-removing work, fulfilled in Christ who 'endured the cross, despising the shame' (Heb 12:2).</p>",
        "10": "<p>The first Passover in the land — on the fourteenth of Nisan at Gilgal — completes the liturgical arc that began with the first Passover in Egypt (Exod 12). The NT's Passover completion is Christ's last supper and death: 'Christ, our Passover lamb, has been sacrificed' (1 Cor 5:7). Jesus died on Passover, the fourteenth of Nisan, the same calendar date as the Gilgal Passover — the type and anti-type sharing the same date. The Gilgal Passover was celebrated in the land at the beginning of the conquest; the cross-Passover was accomplished at the beginning of the new creation's conquest over sin and death. Both are 'in the land' Passovers — eaten by those who have crossed through the waters and arrived.</p>",
        "11": "<p>The eating of the produce of the land on the day after the Passover — the first taste of Canaanite grain — types the new spiritual nourishment available in Christ. Jesus draws precisely this typological line: 'Your fathers ate the manna in the wilderness, and they died... I am the living bread that came down from heaven. If anyone eats of this bread, he will live forever' (John 6:49-51). The transition from manna (miraculous wilderness food) to land produce (ordinary grain made extraordinary by covenant context) types the transition from the provisional sustenance of the law period to the full nourishment of Christ. The Eucharistic bread is this 'produce of the land' — ordinary bread made the body of Christ by covenant institution.</p>",
        "12": "<p>'And the manna ceased the day after they ate of the produce of the land' — the cessation of manna is the definitive ending of the wilderness provision system. 'For the law was given through Moses; grace and truth came through Jesus Christ' (John 1:17). The manna types the law — essential and life-sustaining for the wilderness period, but designed to cease when the land was entered. John 6 makes the typological argument explicit: 'Your fathers ate the manna in the wilderness, and they died.' The manna was good but not ultimate; it sustained life temporarily but could not conquer death. Christ is the bread that ends the manna-era: 'The one who eats this bread will live forever' (John 6:58). The manna's cessation is not loss but fulfillment — the land's produce has arrived.</p>",
        "13": "<p>The appearance of the man with the drawn sword — encountered by Joshua alone, near Jericho, after the Passover — is the narrative's most explicit Christophany. Joshua 'fell on his face to the earth and worshiped' (v.14) — worship, not merely greeting. The command to remove sandals (v.15) identifies the figure's presence as the same divine presence who spoke to Moses at the burning bush (Exod 3:5). The figure is the pre-incarnate Christ, the Angel of YHWH who appears as a warrior throughout the OT: 'He who appeared to Abraham at Mamre, to Jacob at Jabbok, to Moses at Sinai' — the same figure who will be incarnated as Jesus of Nazareth. The drawn sword types both the word of God (Heb 4:12, 'the word of God is living and active, sharper than any two-edged sword') and Christ as the divine warrior whose wrath and grace are both in his hand.</p>",
        "14": "<p>'No; but I am the commander of the army of the LORD. Now I have come' — the Christophany's self-identification is military: the divine warrior taking personal command of the conquest. The NT equivalent is the risen Christ in Revelation 19:11-16: 'Then I saw heaven opened, and behold, a white horse! The one sitting on it is called Faithful and True, and in righteousness he judges and makes war... His name is called the Word of God. And the armies of heaven... were following him on white horses.' The Commander of YHWH's army at Gilgal is the same figure as the Rider on the white horse — the divine warrior who takes command at the beginning of each conquest phase. Joshua's response — prostration and 'what does my lord say to his servant?' — is the only appropriate response to this Commander.</p>",
        "15": "<p>'Take off your sandals from your feet, for the place where you are standing is holy' — the command that repeats Exod 3:5 word for word identifies the pre-incarnate Christ with the one who spoke to Moses at the burning bush. The same presence, the same ground-holiness, the same sandal-removal command: YHWH's commissioning presence before Moses at Sinai and before Joshua at Gilgal is the same pre-incarnate Word who will be incarnated as Jesus. 'Before Abraham was, I am' (John 8:58) — the eternal Word has been appearing and commissioning throughout Israel's history. The holy ground at Gilgal is holy because the incarnate Word who will stand on a hill outside Jerusalem is already present there, commissioning the conquest that is a shadow of the ultimate conquest he will accomplish in his own body.</p>",
    },
}

def main():
    existing = load_comm('christ', 'joshua')
    merge_comm(existing, JOSHUA)
    save_comm('christ', 'joshua', existing)
    total = sum(len(existing.get(ch, {})) for ch in ['1','2','3','4','5'])
    print(f'ch 1-5: {total} verses in output')
    print('Joshua 1-5 christ commentary written.')

if __name__ == '__main__':
    main()
